class Solution {
    public int minOperations(int n) {
        int count = 0;
        while (n != 0) {
            if ((n & 1) == 1) {
                count++;
            }
            n = (n >> 1) + (n & 1) * ((n & 2) >> 1);
        }
        return count;
    }
}
